/**
 * Loads the pre-normalized salary records at build time.
 * This file is server-side only (used during Next.js static generation).
 *
 * The records.json file is generated by: npx tsx scripts/normalize.ts
 * It must be regenerated whenever raw source data changes.
 */

import type { NormalizedRecord } from "@/lib/normalization/types";

// Import as a JSON module — Next.js resolveJsonModule handles this at build time
import recordsData from "@/data/normalized/records.json";

interface RecordsFile {
  _meta: {
    generated_at: string;
    total_records: number;
    pipeline_version: string;
  };
  records: NormalizedRecord[];
}

let _cache: NormalizedRecord[] | null = null;

/**
 * Returns all normalized salary records.
 * Cached after first call.
 */
export function getAllRecords(): NormalizedRecord[] {
  if (_cache) return _cache;
  const data = recordsData as unknown as RecordsFile;
  _cache = data.records;
  return _cache;
}

/**
 * Returns pipeline metadata (generation time, record count, version).
 */
export function getRecordsMeta(): RecordsFile["_meta"] {
  const data = recordsData as unknown as RecordsFile;
  return data._meta;
}
